const item = $input.first();
const bn = Object.keys(item.binary)[0];
const buff = await this.helpers.getBinaryDataBuffer(0, bn);
const pdf_base64 = buff.toString('base64');
const chat_id = $('Telegram Trigger').item.json.message.chat.id;
const filename = $('Telegram Trigger').item.json.message.document.file_name || 'plan.pdf';
return [{ json: { pdf_base64, chat_id, filename } }];

const thumbs = $json.thumbs || [];
const chat_id = $('PDF to Base64').item.json.chat_id;
const pdf_base64 = $('PDF to Base64').item.json.pdf_base64;
const filename = $('PDF to Base64').item.json.filename;
const instruction = `You are classifying pages of an Abu Dhabi villa drawing set. For EACH page image in order, return one label from: site_plan, ground_floor, first_floor, roof_plan, top_roof, section, elevation, area_schedule, stair_detail, service_block, boundary_wall, code_analysis, cover, perspective, other. Also list any anchor tokens you can read from: ROAD, PLOT LIMIT, SECTION A-A, SECTION B-B, AREA CALCULATION, FLOOR AREA, STAIR, RISER, TREAD, ELEVATION, FFL, MAJLIS. Output JSON ONLY: {\"pages\":[{\"index\":1,\"label\":\"\",\"confidence\":0.0,\"anchors\":[]}]}`;
const parts = [{ text: instruction }];
for (const t of thumbs) { parts.push({ text: `PAGE ${t.index}:` }); parts.push({ inline_data: { mime_type: 'image/png', data: t.thumb_png_b64 } }); }
const body = { contents: [{ role: 'user', parts }], generationConfig: { temperature: 0, maxOutputTokens: 8192 } };
return [{ json: { body, chat_id, pdf_base64, filename } }];

const r = $input.first().json;
const meta = $('Build Classifier Request').item.json;
let pageMap = [];
try { let t = r?.candidates?.[0]?.content?.parts?.map(x=>x.text||'').join('') || '';
  t = t.replace(/```json\s*/gi,'').replace(/```/g,'').trim().replace(/,\s*([}\]])/g,'$1');
  const m = t.match(/\{[\s\S]*\}/); if (m) pageMap = (JSON.parse(m[0]).pages) || []; } catch(e) { pageMap = []; }
const routes = { site:['site_plan','boundary_wall','service_block'], floorplan:['ground_floor','first_floor','roof_plan','top_roof'], vertical:['section','elevation','stair_detail'], schedule:['area_schedule','code_analysis','stair_detail'] };
const pick = labels => pageMap.filter(p => labels.includes(p.label)).map(p => p.index);
const routing = { site:pick(routes.site), floorplan:pick(routes.floorplan), vertical:pick(routes.vertical), schedule:pick(routes.schedule) };
const allIdx = pageMap.map(p=>p.index);
for (const k in routing) { if (!routing[k].length) routing[k] = allIdx; }
return [{ json: { pageMap, routing, chat_id: meta.chat_id, pdf_base64: meta.pdf_base64, filename: meta.filename } }];

const pages = $json.pages || [];
const route = $('Parse + Route').item.json;
const instruction = `You are an expert reader of Abu Dhabi villa SITE PLANS and BOUNDARY WALL drawings. All dimensions are in MILLIMETRES. The plot boundary is a dashed/solid PLOT LIMIT line; the road side is marked ROAD or MAIN ROAD. Setbacks are the gaps between PLOT LIMIT and the building wall. For EVERY field return an OBJECT: { \"value\": number|null, \"unit_original\": \"mm\"|\"m\"|\"cm\"|\"sqm\"|\"%\", \"page\": number, \"evidence_text\": \"exact text you read\", \"method\": \"table\"|\"section_mark\"|\"dimension_line\"|\"label\"|\"schedule\", \"confidence\": 0.0 }. Use null value and confidence 0 for anything you cannot actually read. Never guess. Output JSON ONLY: { \"site\": { \"plot_area_sqm\": {}, \"plot_width_m\": {}, \"plot_depth_m\": {} }, \"setbacks\": { \"front_setback_m\": {}, \"rear_setback_m\": {}, \"left_setback_m\": {}, \"right_setback_m\": {} }, \"separations\": { \"villa_to_annex_m\": {} }, \"fence\": { \"height_m\": {} }, \"entrances\": { \"vehicle_count\": {}, \"vehicle_width_m\": {}, \"pedestrian_count\": {}, \"ped_width_m\": {} }, \"pool\": { \"present\": {}, \"barrier_m\": {} }, \"areas\": { \"coverage_pct\": {}, \"open_area_pct\": {} } }`;
const parts = [{ text: instruction }];
for (const p of pages) { parts.push({ text: `PAGE ${p.index} (high-res):` }); parts.push({ inline_data: { mime_type: 'image/png', data: p.full_png_b64 } }); }
const body = { contents: [{ role: 'user', parts }], generationConfig: { temperature: 0, maxOutputTokens: 16384 } };
return [{ json: { body, chat_id: route.chat_id, pdf_base64: route.pdf_base64, filename: route.filename, routing: route.routing, pageMap: route.pageMap } }];

const r = $input.first().json;
const meta = $('Build Site Request').item.json;
let d = {};
try { let t = r?.candidates?.[0]?.content?.parts?.map(x=>x.text||'').join('') || '';
  t = t.replace(/```json\s*/gi,'').replace(/```/g,'').trim().replace(/,\s*([}\]])/g,'$1');
