return [{ json: { module: 'site', extracted: d, chat_id: meta.chat_id, filename: meta.filename, pageMap: meta.pageMap } }];

const pages = $json.pages || [];
const route = $('Parse + Route').item.json;
const instruction = `You are an expert reader of Abu Dhabi villa FLOOR PLANS (ground, first, roof). All dimensions are in MILLIMETRES (e.g. 560 = 5.6m). Room area may appear in a FLOOR AREA box, or as L x W on the label, or must be computed from dimension lines. width_m is the SMALLER room dimension. For EVERY field return an OBJECT: { \"value\": number|null, \"unit_original\": \"mm\"|\"m\"|\"cm\"|\"sqm\"|\"%\", \"page\": number, \"evidence_text\": \"exact text you read\", \"method\": \"table\"|\"section_mark\"|\"dimension_line\"|\"label\"|\"schedule\", \"confidence\": 0.0 }. Use null value and confidence 0 for anything you cannot actually read. Never guess. Output JSON ONLY: { \"rooms\": { \"ground_floor\": [ { \"name\": \"\", \"type\": \"\", \"area\": {}, \"width\": {} } ], \"first_floor\": [ { \"name\": \"\", \"type\": \"\", \"area\": {}, \"width\": {} } ], \"roof_floor\": [ { \"name\": \"\", \"type\": \"\", \"area\": {}, \"width\": {} } ] }, \"kitchen\": { \"main_count\": {}, \"area_sqm\": {}, \"pantry_count\": {} }, \"majlis\": { \"count\": {}, \"main_area_sqm\": {} }, \"corridors\": { \"min_width_m\": {} }, \"doors\": { \"main_entrance_clear_mm\": {}, \"smallest_clear_mm\": {} } }`;
const parts = [{ text: instruction }];
for (const p of pages) { parts.push({ text: `PAGE ${p.index} (high-res):` }); parts.push({ inline_data: { mime_type: 'image/png', data: p.full_png_b64 } }); }
const body = { contents: [{ role: 'user', parts }], generationConfig: { temperature: 0, maxOutputTokens: 16384 } };
return [{ json: { body, chat_id: route.chat_id, pdf_base64: route.pdf_base64, filename: route.filename, routing: route.routing, pageMap: route.pageMap } }];

