const pages = $json.pages || [];
const route = $('Parse + Route').item.json;
const instruction = `You are an expert reader of Abu Dhabi villa SECTIONS, ELEVATIONS and STAIR DETAILS. Plan dimensions are in MILLIMETRES; level marks like +0.30, +4.72, +14.70 are in METRES. FROM THE STAIR DETAIL TABLE read literally: TOTAL HEIGHT, STAIR WIDTH, N.OF STEPS, RISER, TREAD. Riser/Tread like 0.17 / 0.30 mean 17cm/30cm -> convert to mm in value (170/300), set unit_original to what you saw. FROM SECTIONS read level marks to compute floor-to-floor and total height. For EVERY field return an OBJECT: { \"value\": number|null, \"unit_original\": \"mm\"|\"m\"|\"cm\"|\"sqm\"|\"%\", \"page\": number, \"evidence_text\": \"exact text you read\", \"method\": \"table\"|\"section_mark\"|\"dimension_line\"|\"label\"|\"schedule\", \"confidence\": 0.0 }. Use null value and confidence 0 for anything you cannot actually read. Never guess. Output JSON ONLY: { \"heights\": { \"total_building_m\": {}, \"ground_floor_to_floor_m\": {}, \"first_floor_to_floor_m\": {}, \"parapet_m\": {}, \"under_stair_m\": {} }, \"levels\": { \"gf_above_road_m\": {}, \"entrance_above_road_m\": {} }, \"stairs\": { \"count\": {}, \"width_m\": {}, \"riser_mm\": {}, \"tread_mm\": {}, \"headroom_m\": {}, \"flight_rise_m\": {}, \"handrail_mm\": {} } }`;
const parts = [{ text: instruction }];
for (const p of pages) { parts.push({ text: `PAGE ${p.index} (high-res):` }); parts.push({ inline_data: { mime_type: 'image/png', data: p.full_png_b64 } }); }
const body = { contents: [{ role: 'user', parts }], generationConfig: { temperature: 0, maxOutputTokens: 16384 } };
return [{ json: { body, chat_id: route.chat_id, pdf_base64: route.pdf_base64, filename: route.filename, routing: route.routing, pageMap: route.pageMap } }];

const r = $input.first().json;
const meta = $('Build Vert Request').item.json;
let d = {};
try { let t = r?.candidates?.[0]?.content?.parts?.map(x=>x.text||'').join('') || '';
  t = t.replace(/```json\s*/gi,'').replace(/```/g,'').trim().replace(/,\s*([}\]])/g,'$1');
