const pages = $json.pages || [];
const route = $('Parse + Route').item.json;
const instruction = `You are an expert reader of Abu Dhabi villa AREA SCHEDULES, CODE ANALYSIS sheets and DOOR/STAIR tables. Read printed table values exactly. For EVERY field return an OBJECT: { \"value\": number|null, \"unit_original\": \"mm\"|\"m\"|\"cm\"|\"sqm\"|\"%\", \"page\": number, \"evidence_text\": \"exact text you read\", \"method\": \"table\"|\"section_mark\"|\"dimension_line\"|\"label\"|\"schedule\", \"confidence\": 0.0 }. Use null value and confidence 0 for anything you cannot actually read. Never guess. Output JSON ONLY: { \"areas\": { \"ground_floor_sqm\": {}, \"first_floor_sqm\": {}, \"roof_floor_sqm\": {}, \"total_built_sqm\": {}, \"coverage_pct\": {} }, \"building_info\": { \"floors_above_ground\": {}, \"max_height_m\": {} }, \"fire\": { \"smoke_alarms_present\": {} } }`;
const parts = [{ text: instruction }];
for (const p of pages) { parts.push({ text: `PAGE ${p.index} (high-res):` }); parts.push({ inline_data: { mime_type: 'image/png', data: p.full_png_b64 } }); }
const body = { contents: [{ role: 'user', parts }], generationConfig: { temperature: 0, maxOutputTokens: 16384 } };
return [{ json: { body, chat_id: route.chat_id, pdf_base64: route.pdf_base64, filename: route.filename, routing: route.routing, pageMap: route.pageMap } }];

const r = $input.first().json;
const meta = $('Build Sched Request').item.json;
let d = {};
try { let t = r?.candidates?.[0]?.content?.parts?.map(x=>x.text||'').join('') || '';
  t = t.replace(/```json\s*/gi,'').replace(/```/g,'').trim().replace(/,\s*([}\]])/g,'$1');
  const m = t.match(/\{[\s\S]*\}/); if (m) d = JSON.parse(m[0]); } catch(e) { d = { parse_error: e.message }; }
return [{ json: { module: 'sched', extracted: d, chat_id: meta.chat_id, filename: meta.filename, pageMap: meta.pageMap } }];

// Merge node passes 4 items (one per module). Combine their extracted objects.
const items = $input.all();
let extracted = {}; let pageMap = []; let chat_id, filename;
for (const it of items) { const j = it.json; Object.assign(extracted, j.extracted||{}); if ((j.pageMap||[]).length) pageMap = j.pageMap; chat_id = chat_id||j.chat_id; filename = filename||j.filename; }
const labelOf = idx => (pageMap.find(p=>p.index===idx)||{}).label || 'unknown';
const review = [];
function norm(f){ if(!f||typeof f!=='object'||f.value==null) return f; if(f.unit_original==='cm'){f._mm=f.value*10;f._m=f.value/100;} else if(f.unit_original==='mm'){f._mm=f.value;f._m=f.value/1000;} else if(f.unit_original==='m'){f._m=f.value;f._mm=f.value*1000;} else {f._raw=f.value;} return f; }
function gate(name,f){ if(!f||f.value==null){return;} norm(f); if(f.page!=null) f.page_label=labelOf(f.page); if((f.confidence||0)<0.6){f.review=true; review.push({field:name,reason:'low_confidence',conf:f.confidence});} }
function walk(obj,prefix){ for(const k of Object.keys(obj||{})){ const v=obj[k]; if(Array.isArray(v)){ v.forEach((el,i)=>walk(el,`${prefix}${k}[${i}].`)); } else if(v&&typeof v==='object'&&'value' in v){ gate(prefix+k,v); } else if(v&&typeof v==='object'){ walk(v,prefix+k+'.'); } } }
walk(extracted,'');
// source-page rule: setbacks must come from site/boundary pages
const SITE_OK=new Set(['site_plan','boundary_wall']);
for(const k of ['front_setback_m','rear_setback_m','left_setback_m','right_setback_m']){ const f=extracted.setbacks?.[k]; if(f&&f.page_label&&!SITE_OK.has(f.page_label)){f.review=true; review.push({field:'setbacks.'+k,reason:'wrong_source_page',page:f.page_label});} }
// stairs must come from section/elevation/stair_detail
const STAIR_OK=new Set(['section','elevation','stair_detail']);
for(const k of ['width_m','riser_mm','tread_mm','headroom_m','flight_rise_m','handrail_mm']){ const f=extracted.stairs?.[k]; if(f&&f.page_label&&!STAIR_OK.has(f.page_label)){f.review=true; review.push({field:'stairs.'+k,reason:'wrong_source_page',page:f.page_label});} }
// room-area reconciliation vs schedule
const sched=extracted.areas||{};
const floors={ground_floor:sched.ground_floor_sqm?.value, first_floor:sched.first_floor_sqm?.value, roof_floor:sched.roof_floor_sqm?.value};
for(const fl in floors){ const total=floors[fl]; if(!total) continue; const rooms=extracted.rooms?.[fl]||[]; const sum=rooms.reduce((a,r)=>a+(r.area?.value&&r.area.unit_original==='sqm'?r.area.value:0),0); if(sum>0){ const dev=Math.abs(sum-total)/total; if(dev>0.15) review.push({field:fl+'_rooms',reason:'area_mismatch',sum:+sum.toFixed(1),expected:total}); } }
return [{ json: { extracted, review, chat_id, filename } }];

const e = $input.first().json.extracted || {};
const review = $input.first().json.review || [];
const chat_id = $input.first().json.chat_id;
// Rules subset embedded; in production load rules.json instead.
const RULES=[
{id:'S-FRONT',field:'setbacks.front_setback_m',kind:'m',op:'>=',value:1.5,label:'الارتداد الأمامي',part:'A'},
{id:'S-REAR',field:'setbacks.rear_setback_m',kind:'m',op:'>=',value:1.5,label:'الارتداد الخلفي',part:'A'},
{id:'S-LEFT',field:'setbacks.left_setback_m',kind:'m',op:'>=',value:1.5,label:'الارتداد الأيسر',part:'A'},
{id:'S-RIGHT',field:'setbacks.right_setback_m',kind:'m',op:'>=',value:1.5,label:'الارتداد الأيمن',part:'A'},
{id:'COV',field:'areas.coverage_pct',kind:'raw',op:'<=',value:70,label:'نسبة البناء',part:'A'},
{id:'FENCE',field:'fence.height_m',kind:'m',op:'<=',value:4.0,label:'ارتفاع السور',part:'A'},
{id:'HEIGHT',field:'heights.total_building_m',kind:'m',op:'<=',value:18,label:'ارتفاع المبنى',part:'A'},
{id:'STAIR-W',field:'stairs.width_m',kind:'m',op:'>=',value:0.915,label:'عرض الدرج',part:'B'},
{id:'RISER',field:'stairs.riser_mm',kind:'mm',op:'range',min:100,max:195,label:'ارتفاع قائمة الدرج',part:'B'},
{id:'TREAD',field:'stairs.tread_mm',kind:'mm',op:'>=',value:280,label:'عمق نائمة الدرج',part:'B'},
{id:'HEAD',field:'stairs.headroom_m',kind:'m',op:'>=',value:2.05,label:'الخلوص فوق الدرج',part:'B'},
{id:'FLIGHT',field:'stairs.flight_rise_m',kind:'m',op:'<=',value:3.65,label:'ارتفاع قلبة الدرج',part:'B'},
{id:'KIT',field:'kitchen.area_sqm',kind:'raw',op:'>=',value:12,label:'مساحة المطبخ',part:'C'},
{id:'CORR',field:'corridors.min_width_m',kind:'m',op:'>=',value:0.915,label:'عرض الممر',part:'C'},
{id:'DOOR',field:'doors.main_entrance_clear_mm',kind:'mm',op:'>=',value:815,label:'عرض الباب الرئيسي',part:'C'},
{id:'POOL',field:'pool.barrier_m',kind:'m',op:'>=',value:1.2,label:'حاجز المسبح',part:'C',applies_if:()=>e.pool?.present?.value===true}
];
function getf(path){ return path.split('.').reduce((o,k)=>(o||{})[k], e); }
function val(f,kind){ if(!f)return null; if(kind==='mm')return f._mm??null; if(kind==='m')return f._m??null; return f._raw??f.value??null; }
const checks=[];
for(const rule of RULES){ if(rule.applies_if && !rule.applies_if()){continue;} const f=getf(rule.field);
  if(!f||f.value==null||f.review){ checks.push({id:rule.id,part:rule.part,label:rule.label,status:'review',actual:null,required:rule.op==='range'?`${rule.min}-${rule.max}`:`${rule.op} ${rule.value}`}); continue; }
  const v=val(f,rule.kind); let pass;
  if(rule.op==='>=')pass=v>=rule.value; else if(rule.op==='<=')pass=v<=rule.value; else if(rule.op==='range')pass=v>=rule.min&&v<=rule.max;
  const unit=rule.kind==='mm'?'mm':(rule.kind==='m'?'m':'');
  checks.push({id:rule.id,part:rule.part,label:rule.label,status:pass?'pass':'fail',actual:`${v}${unit}`,required:rule.op==='range'?`${rule.min}-${rule.max}mm`:`${rule.op} ${rule.value}`});
}
return [{ json: { checks, review, extracted: e, chat_id } }];

const f=$input.first().json; const checks=f.checks||[]; const review=f.review||[];
const h=t=>(t==null?'':String(t)).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const ps=checks.filter(c=>c.status==='pass').length, fl=checks.filter(c=>c.status==='fail').length, rv=checks.filter(c=>c.status==='review').length;
const pct=(ps+fl)>0?((ps/(ps+fl))*100).toFixed(0):'—';
const risk = fl>3?'عالية':fl>0?'متوسطة':'منخفضة';
let m1=`📋 <b>تقرير الامتثال v11</b>
🏛 أبوظبي — DMT + ADIBC
━━━━━━
✅ نجح: ${ps} | ❌ فشل: ${fl} | 🔍 مراجعة: ${rv}
📊 نسبة الامتثال: <b>${pct}%</b>
🚨 المخاطر: <b>${risk}</b>`;
function section(part,title){ let s=`${title}
━━━━━━
`; const rows=checks.filter(c=>c.part===part); if(!rows.length) return s+'لا يوجد
'; for(const c of rows){ const i=c.status==='pass'?'✅':c.status==='fail'?'❌':'🔍'; s+=`${i} ${h(c.label)}: ${h(c.actual)||'—'} (${h(c.required)})
`; } return s; }
const m2=section('A','📐 <b>الجزء أ: الموقع والارتفاعات</b>');
const m3=section('B','🪜 <b>الجزء ب: الدرج</b>');
const m4=section('C','🚪 <b>الجزء ج: الغرف والمداخل والمسبح</b>');
let m5='🔍 <b>بنود تحتاج مراجعة بصرية</b>
━━━━━━
';
if(review.length){ for(const r of review){ m5+=`• ${h(r.field)} — ${h(r.reason)}${r.conf!=null?` (ثقة ${r.conf})`:''}${r.expected!=null?` (متوقع ${r.expected}، مجموع ${r.sum})`:''}
`; } } else { m5+='لا يوجد — جميع القيم مقروءة بثقة كافية.'; }
m5+='

💡 البنود 🔍 لم تُقرأ بثقة كافية من المخطط وتحتاج تدقيق يدوي.';
return [{ json: { m1, m2, m3, m4, m5, chat_id: f.chat_id } }];
